import sys

def solve(data: str) -> str:
    memberships: dict[str, set[str]] = {}
    for line in data.splitlines():
        if not line.strip():
            continue
        entity, split = line.split(',', 1)
        memberships.setdefault(entity, set()).add(split)
    leaked = sorted(entity for entity, splits in memberships.items() if len(splits) > 1)
    return ' '.join(leaked) if leaked else 'clean'

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
